import{_ as o,c as d,o as t,a4 as a}from"./chunks/framework.C7hkbLDc.js";const p=JSON.parse('{"title":"AgileBot Python SDK Update Notes","description":"","frontmatter":{},"headers":[],"relativePath":"en/1-python/AgileBot_Robot_Python_SDK_ChangeLog.md","filePath":"en/1-python/AgileBot_Robot_Python_SDK_ChangeLog.md"}'),c={name:"en/1-python/AgileBot_Robot_Python_SDK_ChangeLog.md"};function i(n,e,l,r,s,_){return t(),d("div",{"data-pagefind-body":!0},e[0]||(e[0]=[a('<h1 id="agilebot-python-sdk-update-notes" tabindex="-1">AgileBot Python SDK Update Notes <a class="header-anchor" href="#agilebot-python-sdk-update-notes" aria-label="Permalink to “AgileBot Python SDK Update Notes”">​</a></h1><h2 id="1-7-0-0" tabindex="-1">1.7.0.0 Update (2025/5/30) <a class="header-anchor" href="#1-7-0-0" aria-label="Permalink to “1.7.0.0 Update (2025/5/30)”">​</a></h2><ol><li><p>Register Changes</p><ol><li>All registers are now placed under the <code>Registers</code> class, and other <code>Registers</code> will be deprecated in the future.</li><li>Interface names have been changed to <code>read_R</code> , <code>write_R</code> , <code>delete_R</code> , etc.</li><li>The <code>add</code> method has been removed; use <code>write_XX</code> instead.</li><li>The RPC interface for reading and writing registers has been changed to a new RPC that only reads values, improving speed.</li><li><code>read_R</code> , <code>read_MR</code> , <code>read_SR</code> now directly return the corresponding values and execution results.</li></ol></li><li><p>Changes to <code>arm</code> Class Interfaces</p><ol><li>The interfaces <code>get_arm_model_info</code> , <code>get_ctrl_status</code> , <code>get_robot_status</code> , <code>get_servo_status</code> , <code>get_soft_mode</code> , <code>get_version</code> have been changed to return &#39;result + execution status&#39;.</li><li>The interfaces <code>servo_on</code> , <code>servo_off</code> , <code>servo_reset</code> have been moved to the <code>arm</code> class, and will be deprecated under <code>execution</code> in the future.</li></ol></li><li><p>Changes to <code>motion</code> Class</p><ol><li>Payload-related operation interfaces have been moved to <code>motion.payload</code> .</li><li>New interfaces for payload measurement have been added.</li><li>New interfaces <code>get_OVC</code> , <code>set_OVC</code> , <code>get_OAC</code> , <code>set_OAC</code> , <code>get_TF</code> , <code>set_TF</code> , <code>get_UF</code> , <code>set_UF</code> , <code>get_TCS</code> , <code>set_TCS</code> have been added.</li><li>The <code>convert_cart_to_joint_simple</code> interface now includes settings for <code>uf_index</code> and <code>tf_index</code> .</li><li>New interfaces <code>move_joint</code> , <code>move_line</code> , <code>move_circle</code> have been added.</li><li>New interfaces <code>convert_joint_to_cart</code> , <code>convert_cart_to_joint</code> have been added.</li><li>New interfaces <code>enter_position_control</code> , <code>exit_position_control</code> , <code>set_udp_feedback_params</code> have been added.</li></ol></li><li><p>The <code>digital_signals</code> class has been renamed to <code>signals</code> to simplify the name.</p></li><li><p>The <code>execution</code> class has added the <code>execute_bas_script</code> interface for executing scripts.</p></li><li><p>The <code>jogging.move</code> interface has been updated to include step value modification: <code>move(*self*, *aj_num*: *int*, *move_mode*: MoveMode = None, *step_length*: *float* = 0)</code> .</p></li><li><p>A new <code>bas_script</code> class has been added for generating scripts.</p></li><li><p>A new <code>modbus</code> class has been added for direct control of Modbus devices.</p></li></ol><h2 id="1-7-1-3" tabindex="-1">1.7.1.3 Update (2025/7/3) <a class="header-anchor" href="#1-7-1-3" aria-label="Permalink to “1.7.1.3 Update (2025/7/3)”">​</a></h2><ol><li>Fixed the issue where the <code>get_all_active_alarms</code> interface might fail.</li><li>Fixed the internal parameter setting error in <code>move_circle</code> .</li><li>Updated the example programs.</li><li>Added the plugin management class, providing the <code>extension.get_robot_ip</code> interface.</li><li>Added interfaces related to trajectory reproduction.</li></ol>',5)]))}const g=o(c,[["render",i]]);export{p as __pageData,g as default};
